var snapshot_buffer: Array = []
var INTERP_DELAY = 0.1 # seconds

func receive_snapshot(pos: Vector3, timestamp: float):
    snapshot_buffer.append({"pos": pos, "time": timestamp})
    while snapshot_buffer.size() > 10:
        snapshot_buffer.pop_front()

func _process(delta):
    var render_time = Time.get_ticks_msec() / 1000.0 - INTERP_DELAY
    for i in range(snapshot_buffer.size() - 1):
        var a = snapshot_buffer[i]
        var b = snapshot_buffer[i + 1]
        if a.time <= render_time and b.time >= render_time:
            var t = (render_time - a.time) / (b.time - a.time)
            global_position = a.pos.lerp(b.pos, t)
            break

