// Delta compression: send only changed fields
public struct NetState {
    public Vector3 position;
    public float health;
    public int ammo;
}

byte[] EncodeDelta(NetState prev, NetState curr) {
    var writer = new NetworkWriter();
    byte mask = 0;
    if (prev.position != curr.position) { mask |= 1; writer.Write(curr.position); }
    if (prev.health != curr.health) { mask |= 2; writer.Write(curr.health); }
    if (prev.ammo != curr.ammo) { mask |= 4; writer.Write(curr.ammo); }
    return PrependMask(mask, writer);
}

