struct FGOAPAction {
    FName Name;
    TMap<FName, bool> Preconditions;
    TMap<FName, bool> Effects;
    float Cost;
};
// Plan execution: convert plan to BT sequence at runtime
// Each GOAPAction maps to a BTTask

class_name GOAPPlanner
func plan(world_state: Dictionary, goal: Dictionary,
    actions: Array[GOAPAction]) -> Array[GOAPAction]:
    # A* search: each node is a world state
    # Neighbors = actions whose preconditions are met
    # Goal test = goal state satisfied
    var open = [{ state=world_state, plan=[], cost=0.0 }]
    while open.size() > 0:
        var current = open.pop_front()
        if _goal_met(current.state, goal): return current.plan
        for action in actions:
            if _preconditions_met(current.state, action):
                var new_state = _apply_effects(current.state, action)
                open.append({ state=new_state, plan=current.plan + [action], cost=current.cost + action.cost })
    return []

