public static Vector3 Seek(Vector3 pos, Vector3 target, float maxSpeed) {
    Vector3 desired = (target - pos).normalized * maxSpeed;
    return desired;
}
public static Vector3 Flee(Vector3 pos, Vector3 threat, float maxSpeed) {
    return -Seek(pos, threat, maxSpeed);
}
public static Vector3 Arrive(Vector3 pos, Vector3 target, float maxSpeed, float slowRadius) {
    float dist = Vector3.Distance(pos, target);
    float speed = dist < slowRadius ? maxSpeed * (dist / slowRadius) : maxSpeed;
    return (target - pos).normalized * speed;
}

