// Turn queue state machine
public class TurnManager : MonoBehaviour {
    Queue<ICombatant> turnQueue = new();
    ICombatant current;
    public void StartBattle(List<ICombatant> combatants) {
        var sorted = combatants.OrderByDescending(c => c.Speed).ToList();
        foreach (var c in sorted) turnQueue.Enqueue(c);
        NextTurn();
    }
    void NextTurn() {
        if (turnQueue.Count == 0) { EndBattle(); return; }
        current = turnQueue.Dequeue();
        current.OnTurnStart(this);
    }
    public void EndCurrentTurn() {
        if (!current.IsDead) turnQueue.Enqueue(current);
        NextTurn();
    }
}

// TurnManager.h
TArray<TScriptInterface<ICombatant>> TurnQueue;
int32 CurrentIndex = 0;
void StartBattle(TArray<TScriptInterface<ICombatant>> Combatants) {
    TurnQueue = Combatants;
    TurnQueue.Sort([](const auto& A, const auto& B) {
        return A->GetSpeed() > B->GetSpeed();
    });
    NextTurn();
}
void NextTurn() {
    TurnQueue.RemoveAll([](const auto& C) { return C->IsDead(); });
    if (TurnQueue.Num() == 0) { OnBattleEnd.Broadcast(); return; }
    CurrentIndex = CurrentIndex % TurnQueue.Num();
    TurnQueue[CurrentIndex]->OnTurnStart(this);
}
void EndCurrentTurn() { CurrentIndex++; NextTurn(); }

