// Command buffer input
public class InputBuffer {
    struct BufferEntry { public string input; public float time; }
    Queue<BufferEntry> buffer = new();
    float bufferWindow = 0.15f;
    public void RecordInput(string input) {
        buffer.Enqueue(new BufferEntry { input = input, time = Time.time });
    }
    public bool ConsumeSequence(string[] sequence) {
        CleanExpired();
        var entries = buffer.ToArray();
        int matchIdx = 0;
        foreach (var e in entries) {
            if (e.input == sequence[matchIdx]) matchIdx++;
            if (matchIdx == sequence.Length) { buffer.Clear(); return true; }
        }
        return false;
    }
    void CleanExpired() {
        while (buffer.Count > 0 && Time.time - buffer.Peek().time > bufferWindow)
            buffer.Dequeue();
    }
}

