class_name InputBuffer extends Node
var buffer: Array[Dictionary] = []
@export var buffer_window: float = 0.15
func record_input(input_name: String):
    buffer.append({"input": input_name, "time": Time.get_ticks_msec() / 1000.0})
func consume_sequence(sequence: Array[String]) -> bool:
    _clean_expired()
    var match_idx = 0
    for entry in buffer:
        if entry.input == sequence[match_idx]: match_idx += 1
        if match_idx == sequence.size():
            buffer.clear(); return true
    return false
func _clean_expired():
    var now = Time.get_ticks_msec() / 1000.0
    buffer = buffer.filter(func(e): return now - e.time <= buffer_window)

// InputBufferComponent.h
struct FBufferEntry { FName Input; float Time; };
TArray<FBufferEntry> Buffer;
float BufferWindow = 0.15f;
void RecordInput(FName Input) {
    Buffer.Add({Input, GetWorld()->GetTimeSeconds()});
}
bool ConsumeSequence(const TArray<FName>& Sequence) {
    CleanExpired();
    int32 MatchIdx = 0;
    for (auto& E : Buffer) {
        if (E.Input == Sequence[MatchIdx]) MatchIdx++;
        if (MatchIdx == Sequence.Num()) { Buffer.Empty(); return true; }
    }
    return false;
}
void CleanExpired() {
    float Now = GetWorld()->GetTimeSeconds();
    Buffer.RemoveAll([&](const FBufferEntry& E) { return Now - E.Time > BufferWindow; });
}

