// Offline progress calculation
public class OfflineProgress {
    public static double Calculate(double ratePerSec, System.DateTime lastPlayed) {
        var elapsed = (System.DateTime.UtcNow - lastPlayed).TotalSeconds;
        elapsed = System.Math.Min(elapsed, 86400); // cap at 24h
        return ratePerSec * elapsed * 0.5; // 50% efficiency offline
    }
    public static void ApplyOnLogin(GameState state) {
        var earned = Calculate(state.currentRate, state.lastLogout);
        state.currency += earned;
        state.lastLogout = System.DateTime.UtcNow;
        ShowOfflineRewardUI(earned);
    }
}

// OfflineProgressSubsystem.h
double CalculateOfflineGains(double RatePerSec, FDateTime LastPlayed) {
    FTimespan Elapsed = FDateTime::UtcNow() - LastPlayed;
    double Secs = FMath::Min(Elapsed.GetTotalSeconds(), 86400.0);
    return RatePerSec * Secs * 0.5;
}
void ApplyOnLogin(UGameState* State) {
    double Earned = CalculateOfflineGains(State->CurrentRate, State->LastLogout);
    State->Currency += Earned;
    State->LastLogout = FDateTime::UtcNow();
    OnOfflineReward.Broadcast(Earned);
}

