public class Pool<T> where T : class, new() {
    Stack<T> free = new();
    public T Get() => free.Count > 0 ? free.Pop() : new T();
    public void Return(T obj) { free.Push(obj); }
    public void Prewarm(int n) { for (int i=0;i<n;i++) free.Push(new T()); }
    public int FreeCount => free.Count;
}

template<typename T>
class TPool {
    TArray<T*> Free;
public:
    T* Acquire() { return Free.Num()>0 ? Free.Pop() : new T(); }
    void Release(T* Obj) { Free.Push(Obj); }
    void Prewarm(int32 N) { for(int32 i=0;i<N;i++) Free.Push(new T()); }
    ~TPool() { for(auto* P:Free) delete P; }
};

