    public void Enqueue(System.Action a) => queue.Enqueue(a);
    public void Flush() { while(queue.TryDequeue(out var a)) a(); }
}

TQueue<TFunction<void()>, EQueueMode::Mpsc> CmdQueue;
void EnqueueCmd(TFunction<void()> Fn) { CmdQueue.Enqueue(MoveTemp(Fn)); }
